mapper.select:
SELECT EXISTS(
    SELECT 1 FROM common_code_group
    WHERE group_code = #{groupCode}
      AND deleted = 0
)

mapper.update:
UPDATE common_code_group
group_name = #{groupName}, description = #{description}, is_active = #{isActive}, updated_at = NOW(), updated_by = #{updatedBy}
WHERE id = #{id} AND deleted = 0
